// --- Helpers ---

type tableGroup struct {
	Table  string
	Chains []service.PipelineChain
}

func groupChainsByTable(chains []service.PipelineChain) []tableGroup {
	order := make([]string, 0)
	groups := make(map[string][]service.PipelineChain)
	for _, c := range chains {
		if _, exists := groups[c.Table]; !exists {
			order = append(order, c.Table)
		}
		groups[c.Table] = append(groups[c.Table], c)
	}
	result := make([]tableGroup, 0, len(order))
	for _, t := range order {
		result = append(result, tableGroup{Table: t, Chains: groups[t]})
	}
	return result
}

func phaseBadge(phase string) string {
	switch strings.ToLower(phase) {
	case "before":
		return "bg-yellow-400/10 text-yellow-400 ring-yellow-400/20"
	case "after":
		return "bg-blue-400/10 text-blue-400 ring-blue-400/20"
	default:
		return "bg-gray-400/10 text-gray-400 ring-gray-400/20"
	}
}

func countEnabled(entries []service.PipelineEntryInfo) int {
	n := 0
	for _, e := range entries {
		if e.Enabled {
			n++
		}
	}
	return n
}

